use std::str::Chars;
use std::iter::Peekable;

#[derive(Debug, PartialEq)]
enum Token {
    Identifier(String),
    Def,
    Return,
    Number(String),
    OpenParenthesis,
    CloseParenthesis,
    Comma,
    LessThan,
    Colon,
    Newline,
    Indent,
    Dedent,
    EndOfFile,
}

struct Lexer<'a> {
    chars: Peekable<Chars<'a>>,
    current_indent: usize,
    indent_levels: Vec<usize>,
    at_bol: bool, // At Beginning Of Line
}

impl<'a> Lexer<'a> {
    fn new(input: &'a str) -> Self {
        Self {
            chars: input.chars().peekable(),
            current_indent: 0,
            indent_levels: Vec::new(),
            at_bol: true, // Start at the beginning of the line
        }
    }

    fn next_token(&mut self) -> Option<Token> {
        while let Some(&ch) = self.chars.peek() {
            if self.at_bol {
                let mut spaces_count = 0;
                while let Some(&' ') = self.chars.peek() {
                    self.chars.next();
                    spaces_count += 1;
                }
                self.at_bol = spaces_count != 0;

                while self.current_indent > spaces_count {
                    // Pop the last indent level from the stack and emit a Dedent if necessary
                    if let Some(last_indent) = self.indent_levels.pop() {
                        if last_indent == spaces_count {
                            self.current_indent = last_indent;
                            break;
                        } else if last_indent < spaces_count {
                            // This would be an error in Python - mismatched indentation
                            panic!("Unindent does not match any outer indentation level");
                        }
                        self.current_indent = last_indent;
                        return Some(Token::Dedent);
                    }
