                if spaces_count > self.current_indent {
                    self.indent_levels.push(self.current_indent);
                    self.current_indent = spaces_count;
                    return Some(Token::Indent);
                }

                if !self.at_bol {
                    // Reached a line with non-whitespace character
                    self.at_bol = true; // Reset for the next line
                } else {
                    continue; // Line only had spaces, continue to the next character
                }
            }

            // Match and consume the next character of the input
            match ch {
                '#' => {
                    // Skip the comment
                    while let Some(ch) = self.chars.next() {
                        if ch == '\n' {
                            self.at_bol = true;
                            break;
