                '(' => {
                    self.chars.next();
                    Some(Token::OpenParenthesis)
                }
                ')' => {
                    self.chars.next();
                    Some(Token::CloseParenthesis)
                }
                ',' => {
                    self.chars.next();
                    Some(Token::Comma)
                }
                '<' => {
                    self.chars.next();
                    Some(Token::LessThan)
                }
                ':' => {
                    self.chars.next();
                    Some(Token::Colon)
