                ch if ch.is_alphanumeric() || ch == '_' => {
                    let mut identifier = String::new();
                    while let Some(&ch) = self.chars.peek() {
                        if ch.is_alphanumeric() || ch == '_' {
                            identifier.push(self.chars.next().unwrap());
                        } else {
                            break;
                        }
