                        }
                    }
                    Some(Token::Number(number))
                }
                _ => None, // Skip any other character, or handle it depending on the requirements
            }
        }

        // End of input: emit any remaining Dedents, if any
        if !self.indent_levels.is_empty() {
            while let Some(_) = self.indent_levels.pop() {
                return Some(Token::Dedent);
            }
